const raw = $json.body ?? $json;
const headers = $json.headers || {};

const COUNTRIES = {
  cn: { key: 'cn', name: '中国', ssh: 'ssh -p 36000 root@10.20.47.14', legacyRepo: '/root/CN-Intelligent-Alarm-Repair-Assistant', sync: 'archive' },
  th: { key: 'th', name: '泰国', ssh: 'ssh -p 36000 root@192.168.20.236', legacyRepo: '/root/TH-Intelligent-Alarm-Repair-Assistant', sync: 'git' },
  ine: { key: 'ine', name: '印尼', ssh: 'ssh -p 36000 root@192.168.21.236', legacyRepo: '/root/INE-Intelligent-Alarm-Repair-Assistant', sync: 'git' },
  pk: { key: 'pk', name: '巴基斯坦', ssh: 'ssh root@10.20.84.176', legacyRepo: '/root/PK-Intelligent-Alarm-Repair-Assistant', sync: 'git' },
  mx: { key: 'mx', name: '墨西哥', ssh: 'ssh -p 36000 root@172.20.220.165', legacyRepo: '/root/MX-Intelligent-Alarm-Repair-Assistant', sync: 'git' },
  ph: { key: 'ph', name: '菲律宾', ssh: 'ssh root@10.20.10.12', legacyRepo: '/root/PH-Intelligent-Alarm-Repair-Assistant', sync: 'git' },
};

function findValue(value, names) {
  if (!value || typeof value !== 'object') return '';
  if (Array.isArray(value)) {
    for (const item of value) {
      const found = findValue(item, names);
      if (found) return found;
    }
    return '';
  }
  for (const [key, item] of Object.entries(value)) {
    if (names.has(String(key).toLowerCase()) && item !== undefined && item !== null && item !== '') {
      return String(item).trim();
    }
    const found = findValue(item, names);
    if (found) return found;
  }
  return '';
}

function normalizeCountry(value) {
  const text = String(value || '').trim().toLowerCase();
  if (['id', 'indonesia', '印尼'].includes(text)) return 'ine';
  if (['cn', 'china', '中国'].includes(text)) return 'cn';
  if (['th', 'thai', 'thailand', '泰国'].includes(text)) return 'th';
  if (['pk', 'pakistan', '巴基斯坦'].includes(text)) return 'pk';
  if (['mx', 'mexico', '墨西哥'].includes(text)) return 'mx';
  if (['ph', 'philippines', '菲律宾'].includes(text)) return 'ph';
  return text;
}

function inferCountryFromPayload(value) {
  const explicit = findValue(value, new Set(['country', 'country_code', 'countrycode', 'app_country']));
  if (explicit) return explicit;
  const projectName = findValue(value, new Set(['project_name', 'projectname']));
  const workflowName = findValue(value, new Set(['workflow_name', 'workflowname', 'workflow_instance_name', 'workflowinstancename', 'process_definition_name', 'processdefinitionname']));
  const text = `${projectName} ${workflowName}`;
  if (/菲律宾|philippines|\bph\b/i.test(text)) return 'ph';
  if (/印尼|indonesia|\bine\b|\bid\b/i.test(text)) return 'ine';
  if (/中国|china|\bcn\b/i.test(text)) return 'cn';
  if (/泰国|thailand|thai|\bth\b/i.test(text)) return 'th';
  if (/巴基斯坦|pakistan|\bpk\b/i.test(text)) return 'pk';
  if (/墨西哥|mexico|\bmx\b/i.test(text)) return 'mx';
  return '';
}

function shellQuote(value) {
  return `'${String(value).replace(/'/g, `'"'"'`)}'`;
}

function jsonEcho(value) {
  return `printf '%s\\n' ${shellQuote(JSON.stringify(value))}`;
}

function buildSyncCommand(country) {
  const repo = '/root/Global-Intelligent-Alarm-Repair-Assistant';
  const repoUrl = 'https://github.com/chenjiuxuan1/Global-Intelligent-Alarm-Repair-Assistant.git';
  const archiveUrl = 'https://github.com/chenjiuxuan1/Global-Intelligent-Alarm-Repair-Assistant/archive/refs/heads/master.tar.gz';
  if (country.sync === 'archive') {
    return [
      `mkdir -p ${shellQuote(repo)}`,
      `if [ ! -f ${shellQuote(repo + '/tools/ds_failed_auto_retry.py')} ]; then echo '通用重跑脚本不存在，开始用压缩包同步代码'; curl -L --retry 3 --retry-delay 2 --connect-timeout 10 -o /tmp/global-intelligent-alarm-repair-assistant-master.tar.gz ${shellQuote(archiveUrl)} && tar -xzf /tmp/global-intelligent-alarm-repair-assistant-master.tar.gz -C ${shellQuote(repo)} --strip-components=1; fi`,
    ].join('; ');
  }
  return [
    `if [ ! -d ${shellQuote(repo)} ]; then git clone ${shellQuote(repoUrl)} ${shellQuote(repo)}; fi`,
    `cd ${shellQuote(repo)}`,
    `if [ ! -f tools/ds_failed_auto_retry.py ]; then echo '通用重跑脚本不存在，开始拉取最新代码'; git remote set-url origin ${shellQuote(repoUrl)} || true; git fetch origin master && git reset --hard origin/master; fi`,
  ].join('; ');
}

function buildRemoteScript(country, payloadB64, dsToken, requestId) {
  const repo = '/root/Global-Intelligent-Alarm-Repair-Assistant';
  const logFile = `/tmp/${country.key}_ds_failed_auto_retry_${requestId}.log`;
  const sync = buildSyncCommand(country);
  return [
    'set -e',
    sync,
    `cd ${shellQuote(repo)}`,
    'set -a',
    `[ -f ${shellQuote(country.legacyRepo + '/.env.local')} ] && source ${shellQuote(country.legacyRepo + '/.env.local')}`,
    '[ -f .env.local ] && source .env.local',
    'set +a',
    `REQUEST_DS_TOKEN=${shellQuote(dsToken)}`,
    `PAYLOAD_B64=${shellQuote(payloadB64)}`,
    `REQUEST_ID=${shellQuote(requestId)}`,
    `COUNTRY=${shellQuote(country.key)}`,
    `nohup python3 tools/ds_failed_auto_retry.py --country "$COUNTRY" --payload-b64 "$PAYLOAD_B64" --ds-token "$REQUEST_DS_TOKEN" --request-id "$REQUEST_ID" >${shellQuote(logFile)} 2>&1 &`,
    jsonEcho({ accepted: true, country: country.key, country_name: country.name, request_id: requestId, log: logFile }),
  ].join('\n');
}

const countryKey = normalizeCountry(
  inferCountryFromPayload(raw) ||
  headers['x-country'] || headers['X-Country'] || ''
);
const country = COUNTRIES[countryKey];
const requestId = String(raw.request_id || raw.requestId || `${countryKey || 'unknown'}-ds-alert-${Date.now()}`).replace(/[^a-zA-Z0-9_.-]/g, '_');
const dsToken =
  findValue(raw, new Set(['ds_token', 'dstoken', 'token', 'dolphinscheduler_token'])) ||
  String(headers['x-ds-token'] || headers['X-DS-Token'] || '').trim();
const payloadJson = JSON.stringify(raw);
const payloadB64 = Buffer.from(payloadJson, 'utf8').toString('base64');

if (!country) {
  return [{ json: {
    accepted: false,
    valid: false,
    country: countryKey,
    request_id: requestId,
    command: jsonEcho({ accepted: false, valid: false, error: `unsupported country: ${countryKey || '(empty)'}`, request_id: requestId }),
    message: '不支持的国家。country 支持 cn/th/ine/id/pk/mx/ph。'
  }}];
}

const remoteScript = buildRemoteScript(country, payloadB64, dsToken, requestId);
const command = `${country.ssh} ${shellQuote(remoteScript)}`;

return [{ json: {
  accepted: true,
  valid: true,
  country: country.key,
  country_name: country.name,
  request_id: requestId,
  ds_token: dsToken,
  payload_b64: payloadB64,
  command,
  note: '后台会调用 retry_instance，最多 3 次，从失败节点开始执行，每次检查间隔 3 分钟。'
}}];

const stdout = String($json.stdout || '').trim();
const stderr = String($json.stderr || '').trim();
let started = null;
try {
  started = stdout ? JSON.parse(stdout.split(/\n/).filter(Boolean).at(-1)) : null;
} catch (error) {
  started = { raw_stdout: stdout, parse_error: error.message };
}

return [{
  json: {
    accepted: Boolean(started?.accepted),
    country: started?.country || $json.country || '',
    country_name: started?.country_name || $json.country_name || '',
    request_id: started?.request_id || $json.request_id || '',
    background_started: Boolean(started?.accepted),
    runner: started,
    stderr,
    message: started?.accepted
      ? `已接收 ${started.country_name || started.country || ''} DS 失败告警，后台自动重跑任务已启动。`
      : (started?.error || 'DS 失败告警自动重跑未启动')
  }
}];
